// helpers.httpRequest polyfill (task runner sandbox doesn't expose this.helpers)
async function _httpRequest(opts) {
  const method = opts.method || 'GET';
  const url = opts.url;
  const headers = opts.headers || {};
  let bodyStr;
  if (opts.body !== undefined && opts.body !== null) {
    bodyStr = (typeof opts.body === 'string') ? opts.body : JSON.stringify(opts.body);
  }
  const resp = await fetch(url, { method, headers, body: bodyStr });
  const text = await resp.text();
  if (!text) return undefined;
  try { return JSON.parse(text); } catch (_) { return text; }
}

// Get Pending: unified fetch over scene_segments (when uses_segments=true) and scenes (legacy).
// Emits one item per work unit. Each item has {kind, scene_id, segment_id, scene_number,
// segment_number, image_url, duration_seconds, zoom_direction, color_mood, selective_color_element}.

const topicId = $("Webhook Trigger").first().json.body.topic_id;
const supabaseUrl = $env.SUPABASE_URL;
const headers = {
  "apikey": $env.SUPABASE_ANON_KEY,
  "Authorization": "Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY,
};

async function get(url) {
  const r = await _httpRequest({ method: "GET", url, headers });
  if (Array.isArray(r)) return r;
  if (typeof r === "string") { try { return JSON.parse(r); } catch(_) { return []; } }
  return r || [];
}
const fetchJson = get.bind(this);

// 1a. Pending segments with embedded parent scene metadata
const segUrl = supabaseUrl + "/rest/v1/scene_segments?topic_id=eq." + topicId
  + "&clip_status=eq.pending&image_url=not.is.null"
  + "&select=id,scene_id,segment_number,duration_ms,image_url,scenes(scene_number,zoom_direction,color_mood,selective_color_element)"
  + "&order=scene_id.asc,segment_number.asc";
const segs = await fetchJson(segUrl);

// 1b. Pending scenes that do NOT use segments (legacy 1-image-per-scene topics)
const sceneUrl = supabaseUrl + "/rest/v1/scenes?topic_id=eq." + topicId
  + "&clip_status=eq.pending&image_url=not.is.null&uses_segments=not.eq.true"
  + "&select=id,scene_number,image_url,zoom_direction,color_mood,selective_color_element,audio_duration_ms"
  + "&order=scene_number.asc";
const legacyScenes = await fetchJson(sceneUrl);

const items = [];
for (const s of segs) {
  const parent = s.scenes || {};
  items.push({ json: {
    kind: "segment",
    scene_id: s.scene_id,
    segment_id: s.id,
    scene_number: parent.scene_number,
    segment_number: s.segment_number,
    image_url: s.image_url,
    duration_seconds: (s.duration_ms || 8000) / 1000,
    zoom_direction: parent.zoom_direction || "in",
    color_mood: parent.color_mood || "full_natural",
    selective_color_element: parent.selective_color_element || null,
  }});
}
for (const s of legacyScenes) {
  items.push({ json: {
    kind: "scene",
    scene_id: s.id,
    segment_id: null,
    scene_number: s.scene_number,
    segment_number: null,
    image_url: s.image_url,
    duration_seconds: s.audio_duration_ms ? (s.audio_duration_ms / 1000) : 6,
    zoom_direction: s.zoom_direction || "in",
    color_mood: s.color_mood || "full_natural",
    selective_color_element: s.selective_color_element || null,
  }});
}

console.log("Ken Burns: " + segs.length + " segments + " + legacyScenes.length + " legacy scenes pending");

return items;

// Ken Burns: download image -> run FFmpeg -> return clip path
// Supports both per-scene (legacy) and per-segment (new variable-pace) work units.

const item = $input.first().json;
if (item.__empty === true) {
  return [{ json: { success: true, skipped: true, reason: "no_pending" } }];
}

const topicId = $("Webhook Trigger").first().json.body.topic_id;
const sceneNum = String(item.scene_number).padStart(3, "0");
const isSegment = item.kind === "segment";
const segNum = isSegment ? String(item.segment_number).padStart(2, "0") : null;

const duration = (item.duration_seconds || 6).toFixed(1);
const zoomDir = item.zoom_direction || "in";
const colorMood = item.color_mood || "full_natural";
const skipColor = item.selective_color_element ? "1" : "0";

const baseName = isSegment ? `kb_${topicId}_${sceneNum}_${segNum}` : `kb_${topicId}_${sceneNum}`;
const imgPath = `/tmp/production/${baseName}.png`;
const clipPath = `/tmp/production/${baseName}.mp4`;

const { execSync } = require("child_process");
try {
  execSync(`curl -sL -o "${imgPath}" "${item.image_url}"`, { timeout: 30000 });
} catch (e) {
  return [{ json: { success: false, kind: item.kind, scene_id: item.scene_id, segment_id: item.segment_id, scene_number: item.scene_number, segment_number: item.segment_number, error: "Image download failed: " + e.message } }];
}

try {
  const cmd = `bash /tmp/production/ken_burns.sh "${imgPath}" ${duration} ${zoomDir} ${colorMood} "${clipPath}" ${skipColor}`;
  execSync(cmd, { timeout: 120000 });
} catch (e) {
  try { execSync(`rm -f "${imgPath}"`); } catch(_) {}
  return [{ json: { success: false, kind: item.kind, scene_id: item.scene_id, segment_id: item.segment_id, scene_number: item.scene_number, segment_number: item.segment_number, error: "Ken Burns failed: " + e.message } }];
}

try { execSync(`rm -f "${imgPath}"`); } catch(_) {}

return [{ json: {
  success: true,
  kind: item.kind,
  scene_id: item.scene_id,
  segment_id: item.segment_id,
  scene_number: item.scene_number,
  segment_number: item.segment_number,
  clip_path: clipPath,
  duration: parseFloat(duration),
  zoom_direction: zoomDir,
  color_mood: colorMood,
} }];
